package problems;

public class rotatedSortedArray {

    public static void main(String[] args) {
        int[] nums = {3, 4, 5, 1, 2};
        System.out.println("Minimum in rotated sorted array: " + minInRotatedSortedArray(nums));

        int[] nums2 = {4, 5, 6, 7, 0, 1, 2};
        System.out.println("Element found at index: " + searchInRotatedSortedArray(nums2, 0));
    }

    /**
     * Find minimum element in rotated sorted array using binary search.
     * 
     * Time: O(log n), Space: O(1)
     * 
     * Key insight: One half of array is always sorted.
     * If left half is sorted (nums[left] < nums[right]), min is at nums[left].
     * Otherwise, rotation point is in right half.
     */
    public static int minInRotatedSortedArray(int[] nums) {
        int left = 0;
        int right = nums.length - 1;
        int ans = nums[0];

        if (nums.length == 1) return ans;

        while (left <= right) {
            // If this portion is sorted, min is at left
            if (nums[left] < nums[right]) {
                ans = Math.min(ans, nums[left]);
                break;
            }

            int mid = (left + right) / 2;
            ans = Math.min(ans, nums[mid]);

            // Determine which half is sorted
            if (nums[left] <= nums[mid]) {
                // Left half is sorted, min must be in right half
                left = mid + 1;
            } else {
                // Right half is sorted, min must be in left half
                right = mid - 1;
            }
        }

        return ans;
    }

    /**
     * Search for target in rotated sorted array using modified binary search.
     * 
     * Time: O(log n), Space: O(1)
     * 
     * Algorithm:
     * - Identify which half is sorted
     * - Check if target is in sorted half's range
     * - If yes, search sorted half; else search other half
     */
    public static int searchInRotatedSortedArray(int[] nums, int target) {
        int left = 0;
        int right = nums.length - 1;

        while (left <= right) {
            int mid = (left + right) / 2;

            if (nums[mid] == target) return mid;

            // Determine which half is sorted
            if (nums[left] <= nums[mid]) {
                // Left half is sorted
                if (target < nums[left] || target > nums[mid]) {
                    // Target not in sorted left half
                    left = mid + 1;
                } else {
                    // Target in sorted left half
                    right = mid - 1;
                }
            } else {
                // Right half is sorted
                if (target > nums[right] || target < nums[mid]) {
                    // Target not in sorted right half
                    right = mid - 1;
                } else {
                    // Target in sorted right half
                    left = mid + 1;
                }
            }
        }

        return -1;
    }
}

// Example 1 (Find Minimum):
// Input: nums = [3,4,5,1,2]
// Output: 1

// Example 2 (Search):
// Input: nums = [4,5,6,7,0,1,2], target = 0
// Output: 4
